mapper.sql:
SELECT A.CONTRACT_NUM AS contractNum , A.RATE_CD AS addProd , FN_GET_RATENM(A.RATE_CD) AS addProdNm , A.STRT_DT AS strtDt , A.END_DT AS endDt , A.STAT_CD AS statCd , DECODE(A.STAT_CD, 'C', '해지', '사용') AS statNm , B.LST_COM_ACTV_DATE AS openDt , C.FST_RATE_CD AS fstRateCD , FN_GET_RATENM(C.FST_RATE_CD) AS fstRateNm , C.LST_RATE_CD AS lstRateCd , FN_GET_RATENM(C.LST_RATE_CD) AS lstRateNm , SUBSTR(C.INST_INFO, 1, 2) AS dcType , FN_GET_CODENM('CMN0058', SUBSTR(C.INST_INFO, 1, 2)) AS dcTypeNm , C.SALE_PLCY_CD AS salePlcyCd , C.SALE_PLCY_NM AS salePlcyNm , TRIM(SUBSTR(C.FST_MODEL_INFO, 1, 20)) AS fstModelId , TRIM(SUBSTR(C.FST_MODEL_INFO, 21, 30)) AS fstModelNm , B.OPEN_AGNT_CD AS openAgntCd , FN_GET_ORGNM(B.OPEN_AGNT_CD) AS openAgntNm FROM MSP_ADD_PROD_STTC A , MSP_JUO_SUB_INFO B , MSP_REQUEST_DTL C , MSP_RATE_MST D WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND B.CONTRACT_NUM = C.CONTRACT_NUM AND A.RATE_CD = D.RATE_CD
AND A.STRT_DT BETWEEN #{strtDt} AND #{endDt}
AND A.RATE_CD = #{searchName}
AND D.RATE_NM LIKE '%' || #{searchName} || '%'
ORDER BY A.CONTRACT_NUM, A.RATE_CD

mapper.select:
/* SaleSttcMgmtMapper.getAddProdHistList */ SELECT A.RATE_CD AS addProd , B.RATE_NM AS addprodNm , B.BASE_AMT AS baseAmt , A.STRT_DT AS strtDt , A.END_DT AS endDt FROM MSP_ADD_PROD_STTC A , MSP_RATE_MST B WHERE A.RATE_CD = B.RATE_CD
AND A.CONTRACT_NUM = #{contractNum}
ORDER BY A.RATE_CD, A.STRT_DT DESC
